     1→/**
     2→ * @file MCP protocol handler with session management
     3→ * @module server/mcp
     4→ *
     5→ * @remarks
     6→ * This implementation handles multiple concurrent sessions per MCP SDK design:
     7→ * - One Server instance per session
     8→ * - Each Server has its own StreamableHTTPServerTransport
     9→ * - Session isolation and management
    10→ */
    11→
    12→import express from "express";
    13→import { Server } from "@modelcontextprotocol/sdk/server/index.js";
    14→import { StreamableHTTPServerTransport } from "@modelcontextprotocol/sdk/server/streamableHttp.js";
    15→import {
    16→  CreateMessageRequestSchema,
    17→  ListToolsRequestSchema,
    18→  CallToolRequestSchema,
    19→  ListPromptsRequestSchema,
    20→  GetPromptRequestSchema,
    21→  ListResourcesRequestSchema,
    22→  ReadResourceRequestSchema,
    23→} from "@modelcontextprotocol/sdk/types.js";
    24→
    25→import { serverConfig, serverCapabilities } from "../constants/server/server-config.js";
    26→import { sendSamplingRequest } from "../handlers/sampling.js";
    27→import { handleListTools, handleToolCall } from "../handlers/tool-handlers.js";
    28→import { handleListPrompts, handleGetPrompt } from "../handlers/prompt-handlers.js";
    29→import { handleListResources, handleResourceCall } from "../handlers/resource-handlers.js";
    30→import { logger } from "../utils/logger.js";
    31→import { sessionManager } from "./session-manager.js";
    32→import { activeConnections } from "../metrics/index.js";
    33→import { rateLimitMiddleware, validateProtocolVersion, requestSizeLimit } from "./middleware.js";
    34→import type { AuthInfo } from "@modelcontextprotocol/sdk/server/auth/types.js";
    35→import type { AuthenticatedRequest } from "./auth-types.js";
    36→
    37→// Per-session auth context storage
    38→interface SessionAuth {
    39→  /** Mittwald access token propagated via oauth-server */
    40→  accessToken: string;
    41→  refreshToken?: string;
    42→  username: string;
    43→  authenticationMode?: 'bridge' | 'direct-token';
    44→  /** Original OAuth JWT issued by the proxy */
    45→  oauthToken?: string;
    46→  scope?: string;
    47→  resource?: string;
    48→  accessTokenExpiresAt?: Date;
    49→}
    50→
    51→interface SessionInfo {
    52→  server: Server;
    53→  transport: StreamableHTTPServerTransport;
    54→  auth?: SessionAuth;
    55→  createdAt: Date;
    56→  lastAccessed: Date;
    57→}
    58→
    59→// Interface for MCP Handler
    60→export interface IMCPHandler {
    61→  setupRoutes(app: express.Application, authMiddleware: express.RequestHandler): Promise<void>;
    62→  getServerForSession(sessionId: string): Server | undefined;
    63→  getAllServers(): Server[];
    64→  getServer(): Server;
    65→  cleanupSession(sessionId: string): void;
    66→  getActiveSessionCount(): number;
    67→  shutdown(): void;
    68→}
    69→
    70→/**
    71→ * MCP Handler with per-session server instances
    72→ */
    73→export class MCPHandler implements IMCPHandler {
    74→  private sessions = new Map<string, SessionInfo>();
    75→
    76→  // Session cleanup interval (clear sessions older than 1 hour)
    77→  private cleanupInterval: NodeJS.Timeout;
    78→  private readonly SESSION_TIMEOUT_MS = 60 * 60 * 1000; // 1 hour
    79→
    80→  constructor() {
    81→    logger.info('🎯 MCP Handler initializing with session management');
    82→    this.cleanupInterval = setInterval(
    83→      () => {
    84→        this.cleanupOldSessions();
    85→      },
    86→      5 * 60 * 1000,
    87→    );
    88→    logger.debug('⏰ Session cleanup interval set to 5 minutes');
    89→  }
    90→
    91→  /**
    92→   * Creates a new server instance with handlers
    93→   */
    94→  private createServer(sessionId: string, sessionAuth?: SessionAuth): Server {
    95→    // Create new server instance for this session
    96→    const server = new Server(serverConfig, serverCapabilities);
    97→
    98→    // Tools
    99→    server.setRequestHandler(ListToolsRequestSchema, (request) => {
   100→      logger.debug(`📋 [${sessionId}] Listing tools`);
   101→      return handleListTools(request);
   102→    });
   103→
   104→    server.setRequestHandler(CallToolRequestSchema, (request) => {
   105→      logger.debug(`🔧 [${sessionId}] Calling tool: ${request.params.name}`);
   106→
   107→      if (!sessionAuth) {
   108→        throw new Error("Authentication required for tool calls");
   109→      }
   110→
   111→      const authInfo: AuthInfo = {
   112→        token: sessionAuth.accessToken,
   113→        clientId: "mcp-client",
   114→        scopes: ["read"],
   115→        extra: {
   116→          userId: sessionAuth.username,
   117→        },
   118→      };
   119→
   120→      return handleToolCall(request, { sessionId, authInfo });
   121→    });
   122→
   123→    // Prompts
   124→    server.setRequestHandler(ListPromptsRequestSchema, () => {
   125→      logger.debug(`📋 [${sessionId}] Listing prompts`);
   126→      return handleListPrompts();
   127→    });
   128→
   129→    server.setRequestHandler(GetPromptRequestSchema, (request) => {
   130→      logger.debug(`📝 [${sessionId}] Getting prompt: ${request.params.name}`);
   131→      return handleGetPrompt(request);
   132→    });
   133→
   134→    // Resources
   135→    server.setRequestHandler(ListResourcesRequestSchema, () => {
   136→      logger.debug(`📋 [${sessionId}] Listing resources`);
   137→      return handleListResources();
   138→    });
   139→
   140→    server.setRequestHandler(ReadResourceRequestSchema, (request) => {
   141→      logger.debug(`📖 [${sessionId}] Reading resource: ${request.params.uri}`);
   142→
   143→      const authInfo = sessionAuth
   144→        ? {
   145→            token: sessionAuth.accessToken,
   146→            clientId: "mcp-client",
   147→            scopes: ["read"],
   148→            extra: {
   149→              userId: sessionAuth.username,
   150→            },
   151→          }
   152→        : undefined;
   153→
   154→      return handleResourceCall(request, authInfo ? { authInfo } : undefined);
   155→    });
   156→
   157→    // Sampling
   158→    server.setRequestHandler(CreateMessageRequestSchema, (request) => {
   159→      return sendSamplingRequest(request, { sessionId });
   160→    });
   161→
   162→    return server;
   163→  }
   164→
   165→  /**
   166→   * Sets up routes for the Express app
   167→   */
   168→  async setupRoutes(
   169→    app: express.Application,
   170→    authMiddleware: express.RequestHandler,
   171→  ): Promise<void> {
   172→    // Apply middleware stack
   173→    const mcpMiddleware = [
   174→      authMiddleware,
   175→      rateLimitMiddleware(60000, 100), // 100 requests per minute
   176→      validateProtocolVersion,
   177→      requestSizeLimit(10 * 1024 * 1024), // 10MB max
   178→    ];
   179→
   180→    // Main MCP endpoint
   181→    app.all("/mcp", ...mcpMiddleware, (req, res) =>
   182→      this.handleRequest(req as AuthenticatedRequest, res),
   183→    );
   184→  }
   185→
   186→  /**
   187→   * Handles incoming MCP requests with proper session management
   188→   */
   189→  private async handleRequest(req: AuthenticatedRequest, res: express.Response): Promise<void> {
   190→    const startTime = Date.now();
   191→    const clientAddr = req.ip || req.connection.remoteAddress || 'unknown';
   192→    const userAgent = req.get('User-Agent') || 'unknown';
   193→    
   194→    // Enhanced request logging
   195→    logger.info(`💬 [${clientAddr}] MCP request: ${req.method} ${req.path}`, {
   196→      userAgent,
   197→      contentType: req.get('Content-Type'),
   198→      contentLength: req.get('Content-Length'),
   199→      headers: {
   200→        'mcp-session-id': req.headers['mcp-session-id'],
   201→        'x-session-id': req.headers['x-session-id'],
   202→        'authorization': req.headers.authorization ? '[PRESENT]' : '[MISSING]'
   203→      }
   204→    });
   205→
   206→    let sessionId: string | undefined;
   207→    try {
   208→      res.header("Access-Control-Expose-Headers", "mcp-session-id, x-session-id");
   209→      sessionId =
   210→        (req.headers["mcp-session-id"] as string) || (req.headers["x-session-id"] as string);
   211→      const isInitRequest = !sessionId;
   212→      let sessionInfo: SessionInfo | undefined;
   213→      if (isInitRequest) {
   214→        // Create new session for initialization
   215→        sessionId = `session_${Date.now()}_${Math.random().toString(36).substring(2, 11)}`;
   216→        logger.info(`🆕 [${clientAddr}] Creating new session: ${sessionId}`);
   217→
   218→        // Extract auth info if available
   219→        const mittwaldAccessToken = typeof req.auth?.extra?.mittwaldAccessToken === 'string'
   220→          ? req.auth.extra.mittwaldAccessToken
   221→          : undefined;
   222→        const mittwaldRefreshToken = typeof req.auth?.extra?.mittwaldRefreshToken === 'string'
   223→          ? req.auth.extra.mittwaldRefreshToken
   224→          : undefined;
   225→        const mittwaldScope = typeof req.auth?.extra?.mittwaldScope === 'string'
   226→          ? req.auth.extra.mittwaldScope
   227→          : undefined;
   228→        const mittwaldAccessTokenExpiresAtSeconds = typeof req.auth?.extra?.mittwaldAccessTokenExpiresAt === 'number'
   229→          ? req.auth.extra.mittwaldAccessTokenExpiresAt
   230→          : undefined;
   231→        const mittwaldResource = typeof req.auth?.extra?.resource === 'string'
   232→          ? req.auth.extra.resource
   233→          : undefined;
   234→
   235→        const requestAuthMode: SessionAuth['authenticationMode'] =
   236→          req.auth?.extra?.authenticationMode === 'direct-bearer' ? 'direct-token' : 'bridge';
   237→
   238→        const sessionAuth = mittwaldAccessToken
   239→          ? {
   240→              accessToken: mittwaldAccessToken,
   241→              refreshToken: mittwaldRefreshToken,
   242→              username: String(req.auth?.extra?.userId || req.auth?.clientId || "unknown"),
   243→              authenticationMode: requestAuthMode,
   244→              oauthToken: req.auth?.token,
   245→              scope: mittwaldScope,
   246→              resource: mittwaldResource,
   247→              accessTokenExpiresAt: mittwaldAccessTokenExpiresAtSeconds
   248→                ? new Date(mittwaldAccessTokenExpiresAtSeconds * 1000)
   249→                : undefined,
   250→            }
   251→          : undefined;
   252→
   253→        if (sessionAuth) {
   254→          logger.info(`🔐 [${sessionId}] Session authenticated as: ${sessionAuth.username}`, {
   255→            hasMittwaldToken: true,
   256→            hasMittwaldRefresh: !!sessionAuth.refreshToken,
   257→            scope: sessionAuth.scope,
   258→          });
   259→
   260→          await this.persistSessionAuth(sessionId, sessionAuth, req.auth);
   261→        } else {
   262→          logger.warn(`🔓 [${sessionId}] Mittwald access token missing in JWT claims; session will be unauthenticated`, {
   263→            clientId: req.auth?.clientId,
   264→          });
   265→          logger.info(`🔓 [${sessionId}] Session created without authentication`);
   266→        }
   267→
   268→        const server = this.createServer(sessionId, sessionAuth);
   269→        const transport = this.createTransport(sessionId, clientAddr);
   270→        
   271→        try {
   272→          await server.connect(transport);
   273→          logger.debug(`✅ [${sessionId}] Server connected to transport`);
   274→        } catch (error) {
   275→          logger.error(`❌ [${sessionId}] Failed to connect server to transport:`, error);
   276→          throw error;
   277→        }
   278→        
   279→        sessionInfo = {
   280→          server,
   281→          transport,
   282→          auth: sessionAuth,
   283→          createdAt: new Date(),
   284→          lastAccessed: new Date(),
   285→        };
   286→        this.sessions.set(sessionId, sessionInfo);
   287→        activeConnections.inc(); // Track active MCP sessions
   288→        logger.info(`📝 [${clientAddr}] Session ${sessionId} created successfully (Total: ${this.sessions.size})`);
   289→        
   290→        await transport.handleRequest(req, res);
   291→      } else {
   292→        // Find existing session
   293→        if (!sessionId) {
   294→          logger.warn(`⚠️ [${clientAddr}] Request missing session ID`);
   295→          res.status(400).json({
   296→            jsonrpc: "2.0",
   297→            error: {
   298→              code: -32600,
   299→              message: "Invalid Request: Missing session ID",
   300→            },
   301→            id: null,
   302→          });
   303→          return;
   304→        }
   305→
   306→        sessionInfo = this.sessions.get(sessionId);
   307→        if (!sessionInfo) {
   308→          logger.warn(`❌ [${clientAddr}] Session not found: ${sessionId} (Available: ${Array.from(this.sessions.keys()).join(', ')})`);
   309→          res.status(404).json({
   310→            jsonrpc: "2.0",
   311→            error: {
   312→              code: -32001,
   313→              message: "Session not found",
   314→            },
   315→            id: null,
   316→          });
   317→          return;
   318→        }
   319→
   320→        logger.debug(`🔄 [${clientAddr}] Using existing session: ${sessionId}`);
   321→        sessionInfo.lastAccessed = new Date();
   322→
   323→        const persistedSession = await sessionManager.getSession(sessionId);
   324→        if (!persistedSession) {
   325→          logger.warn(`❌ [${clientAddr}] Persisted session missing for ${sessionId}; forcing re-authentication`);
   326→          res.status(401).json({
   327→            jsonrpc: "2.0",
   328→            error: {
   329→              code: -32002,
   330→              message: "Session expired",
   331→            },
   332→            id: null,
   333→          });
   334→          return;
   335→        }
   336→
   337→        let needsServerRecreate = false;
   338→        if (!sessionInfo.auth) {
   339→          sessionInfo.auth = {
   340→            accessToken: persistedSession.mittwaldAccessToken,
   341→            refreshToken: persistedSession.mittwaldRefreshToken,
   342→            username: persistedSession.userId,
   343→            authenticationMode: (persistedSession.authenticationMode as SessionAuth['authenticationMode']) ?? 'bridge',
   344→            oauthToken: req.auth?.token,
   345→            scope: persistedSession.scope,
   346→            resource: persistedSession.resource,
   347→            accessTokenExpiresAt: persistedSession.mittwaldAccessTokenExpiresAt,
   348→          };
   349→          needsServerRecreate = true;
   350→        } else {
   351→          sessionInfo.auth.accessToken = persistedSession.mittwaldAccessToken;
   352→          sessionInfo.auth.refreshToken = persistedSession.mittwaldRefreshToken;
   353→          sessionInfo.auth.scope = persistedSession.scope ?? sessionInfo.auth.scope;
   354→          sessionInfo.auth.resource = persistedSession.resource ?? sessionInfo.auth.resource;
   355→          sessionInfo.auth.accessTokenExpiresAt = persistedSession.mittwaldAccessTokenExpiresAt ?? sessionInfo.auth.accessTokenExpiresAt;
   356→          sessionInfo.auth.username = persistedSession.userId ?? sessionInfo.auth.username;
   357→          sessionInfo.auth.authenticationMode =
   358→            (persistedSession.authenticationMode as SessionAuth['authenticationMode']) ??
   359→            sessionInfo.auth.authenticationMode;
   360→          if (req.auth?.token) {
   361→            sessionInfo.auth.oauthToken = req.auth.token;
   362→          }
   363→        }
   364→
   365→        let authUpdatedFromRequest = false;
   366→        if (req.auth && req.auth.token) {
   367→          const mittwaldAccessToken = typeof req.auth.extra?.mittwaldAccessToken === 'string'
   368→            ? req.auth.extra.mittwaldAccessToken
   369→            : undefined;
   370→          const mittwaldRefreshToken = typeof req.auth.extra?.mittwaldRefreshToken === 'string'
   371→            ? req.auth.extra.mittwaldRefreshToken
   372→            : undefined;
   373→          const mittwaldScope = typeof req.auth.extra?.mittwaldScope === 'string'
   374→            ? req.auth.extra.mittwaldScope
   375→            : undefined;
   376→          const mittwaldResource = typeof req.auth.extra?.resource === 'string'
   377→            ? req.auth.extra.resource
   378→            : undefined;
   379→          const mittwaldAccessExpiresAtSeconds = typeof req.auth.extra?.mittwaldAccessTokenExpiresAt === 'number'
   380→            ? req.auth.extra.mittwaldAccessTokenExpiresAt
   381→            : undefined;
   382→
   383→          if (mittwaldAccessToken && sessionInfo.auth) {
   384→            let credentialsChanged = false;
   385→
   386→            if (sessionInfo.auth.accessToken !== mittwaldAccessToken) {
   387→              sessionInfo.auth.accessToken = mittwaldAccessToken;
   388→              credentialsChanged = true;
   389→            }
   390→
   391→            if (mittwaldRefreshToken && sessionInfo.auth.refreshToken !== mittwaldRefreshToken) {
   392→              sessionInfo.auth.refreshToken = mittwaldRefreshToken;
   393→              credentialsChanged = true;
   394→            }
   395→
   396→            if (mittwaldScope && sessionInfo.auth.scope !== mittwaldScope) {
   397→              sessionInfo.auth.scope = mittwaldScope;
   398→              credentialsChanged = true;
   399→            }
   400→
   401→            if (mittwaldResource && sessionInfo.auth.resource !== mittwaldResource) {
   402→              sessionInfo.auth.resource = mittwaldResource;
   403→              credentialsChanged = true;
   404→            }
   405→
   406→            if (mittwaldAccessExpiresAtSeconds) {
   407→              const expiresAtDate = new Date(mittwaldAccessExpiresAtSeconds * 1000);
   408→              if (!sessionInfo.auth.accessTokenExpiresAt || sessionInfo.auth.accessTokenExpiresAt.getTime() !== expiresAtDate.getTime()) {
   409→                sessionInfo.auth.accessTokenExpiresAt = expiresAtDate;
   410→                authUpdatedFromRequest = true;
   411→              }
   412→            }
   413→
   414→            sessionInfo.auth.oauthToken = req.auth.token;
   415→            sessionInfo.auth.username = String(req.auth.extra?.userId || req.auth.clientId || sessionInfo.auth.username || 'unknown');
   416→
   417→            if (credentialsChanged) {
   418→              needsServerRecreate = true;
   419→              authUpdatedFromRequest = true;
   420→            }
   421→          }
   422→        }
   423→
   424→        if (authUpdatedFromRequest && sessionInfo.auth) {
   425→          await this.persistSessionAuth(sessionId, sessionInfo.auth, req.auth);
   426→        }
   427→
   428→        if (needsServerRecreate) {
   429→          logger.debug(`🔄 [${sessionId}] Updating server authentication context`);
   430→
   431→          try {
   432→            sessionInfo.server.close();
   433→          } catch (error) {
   434→            logger.warn(`⚠️ [${sessionId}] Failed to close existing server before recreation`, {
   435→              error: error instanceof Error ? error.message : String(error),
   436→            });
   437→          }
   438→
   439→          const recreatedServer = this.createServer(sessionId, sessionInfo.auth);
   440→          const existingTransport = sessionInfo.transport;
   441→
   442→          if (typeof (existingTransport as any)._started === 'boolean') {
   443→            (existingTransport as any)._started = false;
   444→          }
   445→
   446→          await recreatedServer.connect(existingTransport);
   447→          sessionInfo.server = recreatedServer;
   448→          logger.debug(`✅ [${sessionId}] Session transport recreated successfully`);
   449→        }
   450→
   451→        // Let the session's transport handle the request
   452→        await sessionInfo.transport.handleRequest(req, res);
   453→      }
   454→
   455→      const duration = Date.now() - startTime;
   456→      logger.info(`✅ [${clientAddr}] MCP request completed in ${duration}ms for session ${sessionId}`);
   457→    } catch (error) {
   458→      const duration = Date.now() - startTime;
   459→      const errorSessionId = sessionId || 'unknown';
   460→      logger.error(`❌ [${clientAddr}] MCP request failed after ${duration}ms`, {
   461→        sessionId: errorSessionId,
   462→        error: error instanceof Error ? error.message : String(error),
   463→        stack: error instanceof Error ? error.stack : undefined,
   464→        userAgent,
   465→      });
   466→
   467→      if (!res.headersSent) {
   468→        res.status(500).json({
   469→          jsonrpc: "2.0",
   470→          error: {
   471→            code: -32603,
   472→            message: "Internal error",
   473→          },
   474→          id: null,
   475→        });
   476→      }
   477→    }
   478→  }
