   480→  /**
   481→   * Clean up old sessions
   482→   */
   483→  private cleanupOldSessions(): void {
   484→    const now = Date.now();
   485→    let cleaned = 0;
   486→    const sessionSummary: string[] = [];
   487→
   488→    for (const [sessionId, sessionInfo] of this.sessions.entries()) {
   489→      const age = now - sessionInfo.lastAccessed.getTime();
   490→      const ageMinutes = Math.floor(age / (60 * 1000));
   491→      
   492→      if (age > this.SESSION_TIMEOUT_MS) {
   493→        // Close server and transport
   494→        try {
   495→          sessionInfo.server.close();
   496→          sessionInfo.transport.close();
   497→          this.sessions.delete(sessionId);
   498→          activeConnections.dec(); // Decrement active sessions count
   499→          cleaned++;
   500→          logger.debug(`🧹 Cleaned up expired session: ${sessionId} (age: ${ageMinutes}min)`);
   501→        } catch (error) {
   502→          logger.error(`❌ Failed to cleanup session ${sessionId}:`, error);
   503→        }
   504→      } else {
   505→        sessionSummary.push(`${sessionId}:${ageMinutes}min`);
   506→      }
   507→    }
   508→
   509→    if (cleaned > 0) {
   510→      logger.info(`🧹 Cleaned up ${cleaned} old sessions. Active: ${this.sessions.size} (${sessionSummary.join(', ')})`);
   511→    }
   512→  }
   513→
   514→  private createTransport(sessionId: string, clientAddr: string): StreamableHTTPServerTransport {
   515→    return new StreamableHTTPServerTransport({
   516→      sessionIdGenerator: () => sessionId,
   517→      onsessioninitialized: (sid) => {
   518→        logger.info(`🔗 [${clientAddr}] Session initialized: ${sid}`);
   519→      },
   520→    });
   521→  }
   522→
   523→  /**
   524→   * Get the server instance for a specific session
   525→   */
   526→  getServerForSession(sessionId: string): Server | undefined {
   527→    const sessionInfo = this.sessions.get(sessionId);
   528→    return sessionInfo?.server;
   529→  }
   530→
   531→  /**
   532→   * Get all active servers
   533→   */
   534→  getAllServers(): Server[] {
   535→    return Array.from(this.sessions.values()).map((info) => info.server);
   536→  }
   537→
   538→  /**
   539→   * Get any server instance (for compatibility)
   540→   */
   541→  getServer(): Server {
   542→    const firstSession = this.sessions.values().next().value;
   543→    if (firstSession) {
   544→      return firstSession.server;
   545→    }
   546→    // Create a temporary server if none exist
   547→    return new Server(serverConfig, serverCapabilities);
   548→  }
   549→
   550→  private async persistSessionAuth(sessionId: string, sessionAuth: SessionAuth, authInfo?: AuthInfo): Promise<void> {
   551→    try {
   552→      const existing = await sessionManager.getSession(sessionId);
   553→
   554→      const expiresAtSeconds = typeof authInfo?.expiresAt === 'number'
   555→        ? authInfo.expiresAt
   556→        : undefined;
   557→      const mittwaldAccessExpiresSeconds = typeof authInfo?.extra?.mittwaldAccessTokenExpiresAt === 'number'
   558→        ? authInfo.extra.mittwaldAccessTokenExpiresAt
   559→        : undefined;
   560→      const mittwaldRefreshExpiresSeconds = typeof authInfo?.extra?.mittwaldRefreshTokenExpiresAt === 'number'
   561→        ? authInfo.extra.mittwaldRefreshTokenExpiresAt
   562→        : undefined;
   563→
   564→      const calculatedAccessExpiresAt = mittwaldAccessExpiresSeconds
   565→        ? new Date(mittwaldAccessExpiresSeconds * 1000)
   566→        : (expiresAtSeconds ? new Date(expiresAtSeconds * 1000) : undefined);
   567→      const expiresAt = calculatedAccessExpiresAt ?? existing?.expiresAt ?? new Date(Date.now() + 60 * 60 * 1000);
   568→
   569→      const refreshTokenExpiresAt = mittwaldRefreshExpiresSeconds
   570→        ? new Date(mittwaldRefreshExpiresSeconds * 1000)
   571→        : existing?.mittwaldRefreshTokenExpiresAt;
   572→
   573→      const scopeSource = typeof authInfo?.extra?.mittwaldScopeSource === 'string'
   574→        ? authInfo.extra.mittwaldScopeSource
   575→        : existing?.scopeSource;
   576→      const requestedScope = typeof authInfo?.extra?.mittwaldRequestedScope === 'string'
   577→        ? authInfo.extra.mittwaldRequestedScope
   578→        : existing?.requestedScope;
   579→      const resource = typeof authInfo?.extra?.resource === 'string'
   580→        ? authInfo.extra.resource
   581→        : (sessionAuth.resource ?? existing?.resource);
   582→
   583→      const scope = sessionAuth.scope ?? existing?.scope;
   584→      const scopes = scope
   585→        ? scope.split(/\s+/).filter(Boolean)
   586→        : existing?.scopes;
   587→
   588→      const ttlSeconds = Math.max(
   589→        60,
   590→        Math.floor(Math.max(expiresAt.getTime() - Date.now(), 0) / 1000)
   591→      );
   592→
   593→      await sessionManager.upsertSession(sessionId, sessionAuth.username, {
   594→        mittwaldAccessToken: sessionAuth.accessToken,
   595→        mittwaldRefreshToken: sessionAuth.refreshToken ?? existing?.mittwaldRefreshToken,
   596→        oauthToken: sessionAuth.oauthToken ?? existing?.oauthToken,
   597→        scope,
   598→        scopeSource,
   599→        requestedScope,
   600→        scopes,
   601→        resource,
   602→        expiresAt,
   603→        mittwaldAccessTokenExpiresAt: sessionAuth.accessTokenExpiresAt ?? calculatedAccessExpiresAt ?? existing?.mittwaldAccessTokenExpiresAt,
   604→        mittwaldRefreshTokenExpiresAt: refreshTokenExpiresAt,
   605→        currentContext: existing?.currentContext || {},
   606→        accessibleProjects: existing?.accessibleProjects,
   607→        authenticationMode: sessionAuth.authenticationMode ?? existing?.authenticationMode,
   608→      }, { ttlSeconds });
   609→    } catch (error) {
   610→      logger.error(`💾 [${sessionId}] Failed to persist session auth`, {
   611→        error: error instanceof Error ? error.message : String(error),
   612→      });
   613→    }
   614→  }
   615→
   616→  /**
   617→   * Clean up session
   618→   */
   619→  cleanupSession(sessionId: string): void {
   620→    const sessionInfo = this.sessions.get(sessionId);
   621→    if (sessionInfo) {
   622→      sessionInfo.server.close();
   623→      sessionInfo.transport.close();
   624→      this.sessions.delete(sessionId);
   625→      activeConnections.dec(); // Decrement active sessions count
   626→      logger.debug(`🧹 Cleaned up session: ${sessionId}`);
   627→    }
