   631→   * Get active session count
   632→   */
   633→  getActiveSessionCount(): number {
   634→    return this.sessions.size;
   635→  }
   636→
   637→  /**
   638→   * Shutdown handler
   639→   */
   640→  shutdown(): void {
   641→    if (this.cleanupInterval) {
   642→      clearInterval(this.cleanupInterval);
   643→    }
   644→
