    });
  } else {
    console.log('No apps found or error occurred');
    console.log('Status:', appsResponse.status);
  }
} catch (error) {
  console.error('Error listing apps:', error.message);
  if (error.response) {
    console.error('Response status:', error.response.status);
    console.error('Response data:', error.response.data);
  }
}

console.log('\n=== LISTING AVAILABLE DEPENDENCY VERSIONS ===\n');

try {
  const depsResponse = await client.app.listSystemsoftwares({});

  if (depsResponse.status === 200 && depsResponse.data) {
    console.log(`Found ${depsResponse.data.length} system software types:\n`);

    // Group by system software name
    const grouped = {};
    depsResponse.data.forEach(software => {
      const name = software.name;
      if (!grouped[name]) {
        grouped[name] = [];
      }
      grouped[name].push(software);
    });

    // Display grouped results
    Object.keys(grouped).sort().forEach(name => {
      const versions = grouped[name];
      console.log(`${name}:`);
      versions.forEach(v => {
        const recommended = v.recommendedVersion ? ' (recommended)' : '';
        console.log(`  - ${v.versionRange}${recommended}`);
      });
      console.log('');
    });
  } else {
    console.log('No system software found or error occurred');
    console.log('Status:', depsResponse.status);
  }
} catch (error) {
  console.error('Error listing system software:', error.message);
  if (error.response) {
    console.error('Response status:', error.response.status);
    console.error('Response data:', error.response.data);
  }
}

